mapper.update:
UPDATE FIXED_RETURN
SET qty = #{qty}, vip = #{vip}, vipLocation = #{vipLocation}, updateDate = now()
WHERE id = #{id}

mapper.select:
SELECT DISTINCT DATE_FORMAT(uploadDate, '%Y-%m-%d') FROM FIXED_RETURN
WHERE store = #{store} AND uploadDate BETWEEN #{startDate} AND #{endDate}
ORDER BY uploadDate
